-- Luke Chapter 9
-- Theme: The Identity and Cost of the Messiah — Confession, Transfiguration, and the Way of the Cross
-- 62 verses

INSERT INTO chapters (book_id, chapter_number, overview, theme, key_word_original, key_word_meaning, outline)
SELECT b.id, 9,
  'Luke 9 is the pivotal chapter of the entire Gospel, the hinge on which the whole narrative turns. It opens with the commissioning of the Twelve (vv.1-6) — the multiplication of Jesus''s ministry through authorized representatives — and the miraculous feeding of 5,000 (vv.10-17) that demonstrates his messianic abundance. These works of power set the stage for the central question of the chapter: "Who do the people say that I am?" Peter''s confession — "The Christ of God" (v.20) — is the theological summit of the Galilean ministry.' ||
  'Immediately following the confession comes the first clear passion prediction (vv.22-27): the Son of Man must suffer, be rejected, be killed, and rise. The necessity is expressed with dei (must) — the same word of divine necessity that runs through Luke (2:49; 4:43; 13:33; 19:5; 24:7). The cross is not an accident but the ordained pathway of the Messiah. The conditions of discipleship (v.23: daily cross-bearing) are inseparable from the confession of Christ.' ||
  'The Transfiguration (vv.28-36) is Luke''s answer to the question the disciples could not yet fully comprehend. On the mountain, Jesus''s glory is unveiled — confirming that the cruciform path is not degradation but the way of the glorified Son. Moses and Elijah appear discussing his "decease" (exodus, v.31) — the very subject the passion prediction announced. The Father''s voice from the cloud authenticates Jesus: "This is my beloved Son: hear him." The disciples are commanded to hear — precisely what the Parable of the Sower demanded of hearers.' ||
  'The remainder of the chapter documents the disciples'' persistent failure to understand, set in jarring contrast to the Transfiguration glory. The demonized boy the disciples could not heal (vv.37-43), the second passion prediction they could not comprehend (vv.44-45), the argument about greatness (vv.46-48), the misguided sectarianism about the unknown exorcist (vv.49-50), and the Samaritan rejection (vv.51-56) all demonstrate that the kingdom way is still deeply foreign to the disciples. The chapter closes with three sayings about radical discipleship (vv.57-62) — the cost that distinguishes true followers.',
  'The Identity and Cost of the Messiah — Confession, Transfiguration, and the Way of the Cross',
  'δεῖ (dei)',
  'dei means it is necessary, it must be — expressing divine compulsion or moral necessity. In Luke 9:22 ("The Son of man must suffer"), it introduces the divine necessity of the cross, rooted not in fate but in the redemptive plan of God. This word of necessity threads through Luke-Acts as a marker of the pre-ordained salvific plan, distinguishing Luke''s theology of the cross from accident or tragedy.',
  '["The Twelve Commissioned and Herod''s Perplexity (vv.1-9)","The Feeding of the Five Thousand (vv.10-17)","Peter''s Confession and the First Passion Prediction (vv.18-27)","The Transfiguration: Glory on the Mountain (vv.28-36)","Failure at the Foot of the Mountain: The Demonized Boy (vv.37-43a)","Second Passion Prediction and Discipleship Controversies (vv.43b-56)","The Cost of Following Jesus: Three Sayings (vv.57-62)"]'
FROM books b WHERE b.name = 'Luke';

INSERT INTO verses (chapter_id, verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
SELECT c.id, v.verse_number, v.kjv_text, v.original_text, v.transliteration, v.study_note, v.doctrinal_note
FROM chapters c
JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'Then he called his twelve disciples together, and gave them power and authority over all devils, and to cure diseases.', 'Συγκαλεσάμενος δὲ τοὺς δώδεκα ἔδωκεν αὐτοῖς δύναμιν καὶ ἐξουσίαν ἐπὶ πάντα τὰ δαιμόνια καὶ νόσους θεραπεύειν·', 'Sunkalesamenos de tous dōdeka edōken autois dunamin kai exousian epi panta ta daimonia kai nosous therapeutein;', 'Jesus delegates both power (dunamin — miraculous capacity) and authority (exousian — legal right and commission). Both are necessary and both are derived gifts. The Twelve receive what they do not possess in themselves, given for the purpose of ministry. The commission to overcome "all devils" (panta ta daimonia) and cure diseases mirrors Jesus''s own mission statement (4:18; 7:22), constituting the Twelve as extensions of his own ministry.', NULL),
  (2, 'And he sent them to preach the kingdom of God, and to heal the sick.', 'καὶ ἀπέστειλεν αὐτοὺς κηρύσσειν τὴν βασιλείαν τοῦ Θεοῦ καὶ ἰᾶσθαι τοὺς ἀσθενεῖς,', 'kai apesteilen autous kērussein tēn basileian tou Theou kai iasthai tous astheneis,', '"Sent them" (apesteilen — apostled them; the verb form of apostolos). The Twelve are formally commissioned as apostles here. The double mandate — preaching the kingdom and healing the sick — insists that the gospel cannot be reduced to words alone. The kingdom comes in both proclamation and demonstration. The message and the miracle belong together as two aspects of one saving reality.', NULL),
  (3, 'And he said unto them, Take nothing for your journey, neither staves, nor scrip, neither bread, neither money; neither have two coats apiece.', 'καὶ εἶπεν πρὸς αὐτούς, Μηδὲν αἴρετε εἰς τὴν ὁδόν, μήτε ῥάβδον μήτε πήραν μήτε ἄρτον μήτε ἀργύριον, μήτε ἀνὰ δύο χιτῶνας ἔχειν.', 'kai eipen pros autous, Mēden airete eis tēn hodon, mēte rhabdon mēte pēran mēte arton mēte argurion, mēte ana duo chitōnas echein.', 'The radical simplicity of the mission orders requires total dependence on God''s provision through hospitality. No staff (rhabdon), no bag (pēran), no bread (arton), no money (argurion), no second tunic (chitōna). The stripping away of every security forces the missionaries to trust in the same God whose kingdom they are preaching. The mission''s credibility depends on the missionaries'' demonstrated faith in God''s provision.', NULL),
  (4, 'And whatsoever house ye enter into, there abide, and thence depart.', 'καὶ εἰς ἣν ἂν οἰκίαν εἰσέλθητε, ἐκεῖ μένετε καὶ ἐκεῖθεν ἐξέρχεσθε.', 'kai eis hēn an oikian eiselthēte, ekei menete kai ekeithen exerchesthe.', '"There abide" — stay in the first house that receives you; do not shop around for better hospitality. Stability of residence prevents any appearance of working for personal material gain. The single-household instruction also reflects trust in God''s initial provision rather than continual seeking for improved conditions. The mission''s credibility requires contentment and simplicity.', NULL),
  (5, 'And whosoever will not receive you, when ye depart from that city, shake off the very dust from your feet for a testimony against them.', 'καὶ ὅσοι ἂν μὴ δέχωνται ὑμᾶς, ἐξερχόμενοι ἀπὸ τῆς πόλεως ἐκείνης καὶ τὸν κονιορτὸν ἀπὸ τῶν ποδῶν ὑμῶν ἀποτινάσσετε εἰς μαρτύριον ἐπ'' αὐτούς.', 'kai hosoi an mē dechōntai humas, exerchomenoi apo tēs poleōs ekeinēs kai ton koniorton apo tōn podōn humōn apotinassete eis marturion ep'' autous.', '"Shake off the very dust" — a Jewish gesture indicating that even the dust of a Gentile land was defiled. Applied here to Jewish cities that reject the gospel, it treats such rejection as comparable to Gentile uncleanness. "For a testimony against them" (eis marturion ep'' autous) — the gesture is a formal witness that the offer was made and refused. The responsibility for the rejection rests with the rejectors.', NULL),
  (6, 'And they departed, and went through the towns, preaching the gospel, and healing every where.', 'ἐξερχόμενοι δὲ διήρχοντο κατὰ τὰς κώμας εὐαγγελιζόμενοι καὶ θεραπεύοντες πανταχοῦ.', 'exerchomenoi de diērchonto kata tas kōmas euangelizomenoi kai therapeuontes pantachou.', '"Everywhere" (pantachou) — the mission was comprehensive. The two participles (euangelizomenoi — gospelizing; therapeuontes — healing) confirm that they carried out exactly what they were commissioned to do. The first mission of the Twelve is a success. Luke does not report any failure here; the disciples will fail later (v.40), but their first deployment is characterized by faithful obedience.', NULL),
  (7, 'Now Herod the tetrarch heard of all that was done by him: and he was perplexed, because that it was said of some, that John was risen from the dead;', 'Ἤκουσεν δὲ Ἡρῴδης ὁ τετράρχης τὰ γινόμενα πάντα, καὶ διηπόρει διὰ τὸ λέγεσθαι ὑπό τινων ὅτι Ἰωάννης ἠγέρθη ἐκ νεκρῶν,', 'Ēkousen de Hērōdēs ho tetrarches ta ginomena panta, kai diēporei dia to legesthai hupo tinōn hoti Iōannēs ēgerthē ek nekrōn,', 'Herod Antipas (tetrarch of Galilee and Perea) is confronted by reports of Jesus''s ministry. His "perplexity" (diēporei — complete bewilderment) is not the response of a neutral observer but of a man tormented by guilt. He executed John (3:19-20) and fears John''s resurrection. The three popular identifications — John risen, Elijah, an old prophet — all miss the truth but testify to the extraordinary impact of Jesus.', NULL),
  (8, 'And of some, that Elias had appeared; and of others, that one of the old prophets was risen again.', 'ὑπό τινων δὲ ὅτι Ἡλίας ἐφάνη, ἄλλων δὲ ὅτι προφήτης τις τῶν ἀρχαίων ἀνέστη.', 'hupo tinōn de hoti Ēlias ephanē, allōn de hoti prophētēs tis tōn archaiōn anestē.', 'The three popular identifications anticipate the options posed to the disciples in v.19. Elijah, expected to return before the Messiah (Mal 4:5), was a natural candidate. "One of the old prophets" reflected the hope for an eschatological prophetic figure (Deut 18:15). These identifications are not without honor — John was greater than any prophet (7:28) — but they are all inadequate for the one who is the Son of God.', NULL),
  (9, 'And Herod said, John have I beheaded: but who is this, of whom I hear such things? And he desired to see him.', 'εἶπεν δὲ Ἡρῴδης, Ἰωάννην ἐγὼ ἀπεκεφάλισα· τίς δέ ἐστιν οὗτος περὶ οὗ ἀκούω τοιαῦτα; καὶ ἐζήτει ἰδεῖν αὐτόν.', 'eipen de Hērōdēs, Iōannēn egō apekephalisa; tis de estin houtos peri hou akouō toiauta? kai ezētei idein auton.', '"John have I beheaded" — a casual reference to his own murderous act, revealing Herod''s moral desensitization. "Who is this?" (tis de estin houtos) — the question that runs through chapters 7-9 and is about to receive its definitive answer in v.20. Herod''s curiosity (he will finally see Jesus at the trial, 23:8-12) is idle curiosity, not genuine seeking. He "desired to see" a wonder-worker, not the Lord.', NULL),
  (10, 'And the apostles, when they were returned, told him all that they had done. And he took them, and went aside privately into a desert place belonging to the city called Bethsaida.', 'Καὶ ὑποστρέψαντες οἱ ἀπόστολοι διηγήσαντο αὐτῷ ὅσα ἐποίησαν. καὶ παραλαβὼν αὐτοὺς ὑπεχώρησεν κατ'' ἰδίαν εἰς πόλιν καλουμένην Βηθσαϊδά.', 'Kai hupostrepsantes hoi apostoloi diēgēsanto autō hosa epoiēsan. kai paralabōn autous hupechōrēsen kat'' idian eis polin kaloumenēn Bēthsaida.', 'The Twelve return and report their mission to Jesus. He takes them to a "desert place" (erēmon topon) near Bethsaida for rest and debriefing — a pattern of withdrawal after intense ministry. Bethsaida was Philip''s tetrarchy, outside Herod Antipas''s jurisdiction. The private retreat is interrupted by the crowds, which sets up the feeding miracle.', NULL),
  (11, 'And the people, when they knew it, followed him: and he received them, and spake unto them of the kingdom of God, and healed them that had need of healing.', 'οἱ δὲ ὄχλοι γνόντες ἠκολούθησαν αὐτῷ· καὶ ἀποδεξάμενος αὐτοὺς ἐλάλει αὐτοῖς περὶ τῆς βασιλείας τοῦ Θεοῦ, καὶ τοὺς χρείαν ἔχοντας θεραπείας ἰᾶτο.', 'hoi de ochloi gnontes ēkolouthēsan autō; kai apodexamenos autous elalei autois peri tēs basileias tou Theou, kai tous chreian echontas therapeias iato.', 'Jesus "received them" (apodexamenos — welcomed, accepted with grace). The retreat is interrupted but the hospitality is gracious, not resentful. He speaks of the kingdom and heals those who need healing — the same double mandate he gave the Twelve (v.2). The miracle that follows will reveal the messianic abundance of the kingdom in a way no lecture could.', NULL),
  (12, 'And when the day began to wear away, then came the twelve, and said unto him, Send the multitude away, that they may go into the towns and country round about, and lodge, and get victuals: for we are here in a desert place.', 'Ἡ δὲ ἡμέρα ἤρξατο κλίνειν· προσελθόντες δὲ οἱ δώδεκα εἶπον αὐτῷ, Ἀπόλυσον τὸν ὄχλον, ἵνα πορευθέντες εἰς τὰς κύκλῳ κώμας καὶ ἀγροὺς καταλύσωσιν καὶ εὕρωσιν ἐπισιτισμόν· ὅτι ὧδε ἐν ἐρήμῳ τόπῳ ἐσμέν.', 'Hē de hēmera ērxato klinein; proselthontes de hoi dōdeka eipon autō, Apoluon ton ochlon, hina poreuthentes eis tas kuklō kōmas kai agrous katalusōsin kai heurōsin episitismon; hoti hōde en erēmō topō esmen.', 'The disciples'' practical concern is reasonable: it is late, remote, and the crowd has not eaten. Their solution — "send them away" — is the solution of limitation. They see the crowd as a problem to be dispersed, not a multitude to be fed. Jesus''s counter-command ("give ye them to eat," v.13) reframes their perception entirely: the disciples themselves are the agent of God''s provision for the crowd.', NULL),
  (13, 'But he said unto them, Give ye them to eat. And they said, We have no more but five loaves and two fishes; except we should go and buy meat for all this people.', 'εἶπεν δὲ πρὸς αὐτούς, Δότε αὐτοῖς ὑμεῖς φαγεῖν. οἱ δὲ εἶπον, Οὐκ εἰσὶν ἡμῖν πλεῖον ἢ ἄρτοι πέντε καὶ ἰχθύες δύο, εἰ μήτι πορευθέντες ἡμεῖς ἀγοράσωμεν εἰς πάντα τὸν λαὸν τοῦτον βρώματα.', 'eipen de pros autous, Dote autois humeis phagein. hoi de eipon, Ouk eisin hēmin pleion ē artoi pente kai ichthues duo, ei mēti poreuthentes hēmeis agorasōmen eis panta ton laon touton brōmata.', '"Give ye them to eat" (Dote autois humeis phagein) — the command places the responsibility on the disciples. They respond with an inventory of inadequacy: five loaves, two fish. The number is perfectly insufficient by any human calculation. But Jesus takes insufficient human resources, blesses them, and produces miraculous abundance. The disciples'' inadequacy is the necessary condition for the demonstration of divine sufficiency.', NULL),
  (14, 'For they were about five thousand men. And he said to his disciples, Make them sit down by fifties in a company.', 'ἦσαν γὰρ ὡσεὶ ἄνδρες πεντακισχίλιοι. εἶπεν δὲ πρὸς τοὺς μαθητὰς αὐτοῦ, Κατακλίνατε αὐτοὺς κλισίας ὡσεὶ ἀνὰ πεντήκοντα.', 'ēsan gar hōsei andres pentakischilioi. eipen de pros tous mathētas autou, Kataklinete autous klisias hōsei ana pentēkonta.', '"About five thousand men" (andres — males, not counting women and children, Matt 14:21, so the total crowd was considerably larger). The organization into groups of fifty recalls the organization of Israel in the wilderness (Exod 18:21-25) and the camps of Qumran, evoking Exodus typology: Jesus is providing manna for the new Israel in a new desert. The orderly seating also facilitates the efficient distribution of the miracle.', NULL),
  (15, 'And they did so, and made them all sit down.', 'καὶ ἐποίησαν οὕτως καὶ κατέκλιναν ἅπαντας.', 'kai epoiēsan houtōs kai kateklinan hapantas.', 'The disciples'' obedient action in making thousands sit down in the wilderness before any visible provision is itself an act of faith. They are acting on Jesus''s word before the miracle occurs. This kind of obedient anticipation is the pattern of kingdom discipleship: act as though the provision is already given, because the word of Jesus is more reliable than visible evidence.', NULL),
  (16, 'Then he took the five loaves and the two fishes, and looking up to heaven, he blessed them, and brake, and gave to the disciples to set before the multitude.', 'λαβὼν δὲ τοὺς πέντε ἄρτους καὶ τοὺς δύο ἰχθύας, ἀναβλέψας εἰς τὸν οὐρανόν, εὐλόγησεν αὐτοὺς καὶ κατέκλασεν, καὶ ἐδίδου τοῖς μαθηταῖς παρατιθέναι τῷ ὄχλῳ.', 'labōn de tous pente artous kai tous duo ichthuas, anablepsas eis ton ouranon, eulogēsen autous kai kateklasen, kai edidou tois mathētais paratithenai tō ochlō.', 'Four eucharistic actions: took, blessed, broke, gave. These identical four actions appear at the Last Supper (22:19) and at Emmaus (24:30), deliberately linking the feeding miracle to the sacramental meal. Jesus does not multiply the bread privately then distribute it; he gives it to the disciples to distribute. They are the mediators of his provision — a model of apostolic ministry. The imperfect tense "was giving" (edidou) suggests continuous giving.', NULL),
  (17, 'And they did eat, and were all filled: and there was taken up of fragments that remained to them twelve baskets.', 'καὶ ἔφαγον καὶ ἐχορτάσθησαν πάντες, καὶ ἤρθη τὸ περισσεῦσαν αὐτοῖς κλασμάτων κόφινοι δώδεκα.', 'kai ephagon kai echortasthēsan pantes, kai ērthē to perisseusan autois klasmatōn kophinoi dōdeka.', '"Were all filled" (echortasthēsan — satisfied, fully satiated; from chortos, pasture/grass for animals, i.e., filled to contentment). The kingdom provides abundantly and without lack. "Twelve baskets" of fragments — twelve corresponding to the twelve tribes of Israel, symbolizing messianic provision for all God''s people. The surplus is greater than the original supply; the miracle produced more than was needed, with enough left over to feed the twelve disciples themselves.', NULL),
  (18, 'And it came to pass, as he was alone praying, his disciples were with him: and he asked them, saying, Whom do the crowds say that I am?', 'Καὶ ἐγένετο ἐν τῷ εἶναι αὐτὸν προσευχόμενον κατὰ μόνας, συνῆσαν αὐτῷ οἱ μαθηταί, καὶ ἐπηρώτησεν αὐτοὺς λέγων, Τίνα με λέγουσιν οἱ ὄχλοι εἶναι;', 'Kai egeneto en tō einai auton proseuchomenon kata monas, sunēsan autō hoi mathētai, kai epērōtēsen autous legōn, Tina me legousin hoi ochloi einai?', 'The confession scene is prefaced by prayer — uniquely in Luke. Jesus is praying alone (kata monas — in solitude) when the disciples join him, and out of that prayerful solitude the crucial question arises. Luke consistently links pivotal moments to Jesus''s prayer life (3:21; 6:12; 9:28; 22:41). The question "Whom do the crowds say that I am?" moves from the popular (vv.7-8) to the personal (v.20).', NULL),
  (19, 'They answering said, John the Baptist; but some say, Elias; and others say, that one of the old prophets is risen again.', 'οἱ δὲ ἀποκριθέντες εἶπον, Ἰωάννην τὸν Βαπτιστήν· ἄλλοι δὲ Ἠλίαν· ἄλλοι δὲ ὅτι προφήτης τις τῶν ἀρχαίων ἀνέστη.', 'hoi de apokrithentes eipon, Iōannēn ton Baptistēn; alloi de Ēlian; alloi de hoti prophētēs tis tōn archaiōn anestē.', 'The three popular opinions recapitulate Herod''s perplexity (vv.7-8). All three are honorable identifications — John the greatest of prophets, Elijah the expected forerunner, an ancient prophet risen. But all three are inadequate. They place Jesus in the prophetic category without recognizing his unique divine sonship. The crowds'' perception, however admiring, falls short of saving knowledge.', NULL),
  (20, 'He said unto them, But whom say ye that I am? Peter answering said, The Christ of God.', 'εἶπεν δὲ αὐτοῖς, Ὑμεῖς δὲ τίνα με λέγετε εἶναι; Πέτρος δὲ ἀποκριθεὶς εἶπεν, Τὸν Χριστὸν τοῦ Θεοῦ.', 'eipen de autois, Humeis de tina me legete einai? Petros de apokritheis eipen, Ton Christon tou Theou.', '"But whom say ye?" (Humeis de — but you, emphatic pronoun) — the question to the disciples is personal, direct, and urgent. Peter''s answer is "The Christ of God" (Ton Christon tou Theou) — Luke''s distinctive form, more theocentric than Matthew''s "Son of the living God." Christos is the Greek translation of Hebrew Mashiach — the anointed one. Peter''s confession is the turning point of the Galilean ministry and the foundation on which Jesus builds his passion teaching.', NULL),
  (21, 'And he straitly charged them, and commanded them to tell no man that thing;', 'ὁ δὲ ἐπιτιμήσας αὐτοῖς παρήγγειλεν μηδενὶ λέγειν τοῦτο,', 'ho de epitimēsas autois parēngeilen mēdeni legein touto,', 'The command to silence (the "messianic secret") follows the confession. The restraint is not denial but timing — the confession without the cross would be a misunderstanding. The crowds'' messianic expectations were political and triumphal; announcement of messiahship without the passion would have ignited those expectations prematurely and misrepresentatively. The disciples must hear the passion prediction (v.22) before the confession can be proclaimed.', NULL),
  (22, 'Saying, The Son of man must suffer many things, and be rejected of the elders and chief priests and scribes, and be slain, and be raised the third day.', 'εἰπὼν ὅτι Δεῖ τὸν Υἱὸν τοῦ ἀνθρώπου πολλὰ παθεῖν καὶ ἀποδοκιμασθῆναι ἀπὸ τῶν πρεσβυτέρων καὶ ἀρχιερέων καὶ γραμματέων καὶ ἀποκτανθῆναι καὶ τῇ τρίτῃ ἡμέρᾳ ἐγερθῆναι.', 'eipōn hoti Dei ton Huion tou anthrōpou polla pathein kai apodokimasthēnai apo tōn presbuterōn kai archiereōn kai grammateōn kai apoktanthēnai kai tē tritē hēmera egerthēnai.', '"Must" (Dei — divine necessity). The first passion prediction contains five elements: (1) suffer many things; (2) be rejected (apodokimasthēnai — tested and found wanting, as a stone rejected by builders — Ps 118:22); (3) by the three constituent parts of the Sanhedrin (elders, chief priests, scribes); (4) be killed; (5) rise the third day. The full plan of redemption is announced in one sentence. The resurrection is not an afterthought but the goal.', NULL),
  (23, 'And he said to them all, If any man will come after me, let him deny himself, and take up his cross daily, and follow me.', 'Ἔλεγεν δὲ πρὸς πάντας, Εἴ τις θέλει ὀπίσω μου ἔρχεσθαι, ἀρνησάσθω ἑαυτόν, καὶ ἀράτω τὸν σταυρὸν αὐτοῦ καθ'' ἡμέραν, καὶ ἀκολουθείτω μοι.', 'Elegen de pros pantas, Ei tis thelei opisō mou erchesthai, arnēsasthō heauton, kai aratō ton stauron autou kath'' hēmeran, kai akoloutheitō moi.', '"To them all" — the conditions of discipleship are not for a spiritual elite but for all followers. "Deny himself" (arnēsasthō heauton) — renounce the self as the center and authority of one''s life. "Take up his cross daily" — Luke uniquely adds "daily" (kath'' hēmeran), making cross-bearing a continuous habitual practice, not merely a crisis decision. The cross is the posture of self-giving love, not merely physical martyrdom.', NULL),
  (24, 'For whosoever will save his life shall lose it: but whosoever will lose his life for my sake, the same shall save it.', 'ὃς γὰρ ἂν θέλῃ τὴν ψυχὴν αὐτοῦ σῴζειν ἀπολέσει αὐτήν· ὃς δ'' ἂν ἀπολέσῃ τὴν ψυχὴν αὐτοῦ ἕνεκεν ἐμοῦ, οὗτος σώσει αὐτήν.', 'hos gar an thelē tēn psuchēn autou sōzein apolesei autēn; hos d'' an apolesē tēn psuchēn autou heneken emou, houtos sōsei autēn.', 'The paradox of discipleship: the life saved by self-preservation is the life that is ultimately lost; the life surrendered for Christ''s sake is the life ultimately saved. "Life" (psuchē) refers to the self, the whole person, the very thing one considers most precious. The verse describes the fundamental inversion of the kingdom: power through weakness, life through death, gain through surrender. This is the logic of the cross applied to every disciple.', NULL),
  (25, 'For what is a man advantaged, if he gain the whole world, and lose himself, or be cast away?', 'τί γὰρ ὠφελεῖται ἄνθρωπος κερδήσας τὸν κόσμον ὅλον, ἑαυτὸν δὲ ἀπολέσας ἢ ζημιωθείς;', 'ti gar ōpheleitai anthrōpos kerdēsas ton kosmon holon, heauton de apolesas ē zēmiōtheis?', 'A rhetorical question that illuminates ultimate values. The entire world''s resources, power, and pleasures cannot compensate for the loss of the self that was made for God. "Lose himself" (heauton apolesas — to destroy oneself) and "be cast away" (zēmiōtheis — to forfeit, suffer damage/loss) describe two ways of soul-ruin. The devil offered Jesus the whole world (4:6); Jesus rejected it for the same reason this verse articulates.', NULL),
  (26, 'For whosoever shall be ashamed of me and of my words, of him shall the Son of man be ashamed, when he shall come in his own glory, and in his Father''s, and of the holy angels.', 'ὃς γὰρ ἂν ἐπαισχυνθῇ με καὶ τοὺς ἐμοὺς λόγους, τοῦτον ὁ Υἱὸς τοῦ ἀνθρώπου ἐπαισχυνθήσεται, ὅταν ἔλθῃ ἐν τῇ δόξῃ αὐτοῦ καὶ τοῦ Πατρὸς καὶ τῶν ἁγίων ἀγγέλων.', 'hos gar an epaischunthē me kai tous emous logous, touton ho Huios tou anthrōpou epaischunthēsetai, hotan elthē en tē doxē autou kai tou Patros kai tōn hagiōn angelōn.', '"Ashamed of me and of my words" — shame is the social emotion that seeks approval from humans rather than from God. It fears the ridicule of the world more than the judgment of God. The consequence: the Son of Man will be "ashamed" of such a person at the Parousia. The threefold glory — his own, the Father''s, and the angels'' — contrasts with the humble, cross-bearing form of his present coming, confirming that the exalted Christ will vindicate those who were faithful in his humiliation.', NULL),
  (27, 'But I tell you of a truth, there be some standing here, which shall not taste of death, till they see the kingdom of God.', 'λέγω δὲ ὑμῖν ἀληθῶς, εἰσίν τινες τῶν ὧδε ἑστηκότων οἳ οὐ μὴ γεύσωνται θανάτου ἕως ἂν ἴδωσιν τὴν βασιλείαν τοῦ Θεοῦ.', 'legō de humin alēthōs, eisin tines tōn hōde hestēkotōn hoi ou mē geusōntai thanatou heōs an idōsin tēn basileian tou Theou.', '"Some standing here" most naturally refers to Peter, James, and John who will witness the Transfiguration six days later — "the kingdom of God come with power" (Mark 9:1) is fulfilled in that preview of glory. Others have interpreted it as the resurrection appearances, Pentecost, or the destruction of Jerusalem. The Transfiguration interpretation (immediately following in all three Synoptics) is most contextually coherent.', NULL),
  (28, 'And it came to pass about an eight days after these sayings, he took Peter and John and James, and went up into a mountain to pray.', 'Ἐγένετο δὲ μετὰ τοὺς λόγους τούτους ὡσεὶ ἡμέραι ὀκτὼ καὶ παραλαβὼν Πέτρον καὶ Ἰωάννην καὶ Ἰάκωβον ἀνέβη εἰς τὸ ὄρος προσεύξασθαι.', 'Egeneto de meta tous logous toutous hōsei hēmerai oktō kai paralabōn Petron kai Iōannēn kai Iakōbon anebē eis to oros proseuxasthai.', 'Luke alone says "about eight days" (Matthew and Mark say "after six days" — Luke uses the inclusive reckoning). The mountain is not named; tradition identifies it as Mount Tabor or Hermon. Luke uniquely notes the purpose: "to pray" (proseuxasthai). The Transfiguration occurs in the context of prayer — another Lukan signature of prayer at pivotal moments (3:21; 6:12; 22:41).', NULL),
  (29, 'And as he prayed, the fashion of his countenance was altered, and his raiment was white and glistering.', 'καὶ ἐγένετο ἐν τῷ προσεύχεσθαι αὐτὸν τὸ εἶδος τοῦ προσώπου αὐτοῦ ἕτερον, καὶ ὁ ἱματισμὸς αὐτοῦ λευκὸς ἐξαστράπτων.', 'kai egeneto en tō proseuchesthai auton to eidos tou prosōpou autou heteron, kai ho himatismos autou leukos exastraptōn.', '"As he prayed" — the transformation occurs during prayer. Luke is unique in this detail, connecting the Transfiguration directly to the prayer. "The fashion of his countenance was altered" (heteron — different, other). "White and glistering" (exastraptōn — dazzling, blazing like lightning). This is the shekinah glory — the radiant presence of God made visible in Christ''s body. The divine glory that was veiled in the Incarnation is momentarily unveiled.', NULL),
  (30, 'And, behold, there talked with him two men, which were Moses and Elias:', 'καὶ ἰδοὺ ἄνδρες δύο συνελάλουν αὐτῷ, οἵτινες ἦσαν Μωϋσῆς καὶ Ἠλίας,', 'kai idou andres duo sunelaloun autō, hoitines ēsan Mōusēs kai Ēlias,', 'Moses and Elijah represent the Law and the Prophets — the entire OT witness to Christ. Their appearance with Jesus confirms that he is the fulfilment of all Scripture. Moses (who died and whose body was mysterious — Deut 34:6) and Elijah (who was taken alive — 2 Kgs 2:11) represent both types of exit from this world, confirming that both resurrection and translation serve the same divine purpose.', NULL),
  (31, 'Who appeared in glory, and spake of his decease which he should accomplish at Jerusalem.', 'οἳ ὀφθέντες ἐν δόξῃ ἔλεγον τὴν ἔξοδον αὐτοῦ ἣν ἤμελλεν πληροῦν ἐν Ἱερουσαλήμ.', 'hoi ophthentes en doxē elegon tēn exodon autou hēn ēmellen plēroun en Hierousalēm.', '"His decease" (exodon — Exodus). Luke uniquely reveals the subject of the heavenly conversation: the departure/exodus of Jesus to be accomplished in Jerusalem. The word exodos is profound: it echoes the great Exodus from Egypt, casting Jesus''s death-resurrection as the new Exodus — the definitive liberation from the slavery of sin and death. Moses and Elijah discuss the very event the disciples struggle to accept (v.45): the cross is the great Exodus.', NULL),
  (32, 'But Peter and they that were with him were heavy with sleep: and when they were awake, they saw his glory, and the two men that stood with him.', 'ὁ δὲ Πέτρος καὶ οἱ σὺν αὐτῷ ἦσαν βεβαρημένοι ὕπνῳ· διαγρηγορήσαντες δὲ εἶδον τὴν δόξαν αὐτοῦ καὶ τοὺς δύο ἄνδρας τοὺς συνεστῶτας αὐτῷ.', 'ho de Petros kai hoi sun autō ēsan bebarēmenoi hupnō; diagrēgorēsantes de eidon tēn doxan autou kai tous duo andras tous sunestōtas autō.', '"Heavy with sleep" (bebarēmenoi hupnō — weighed down by sleep). The disciples were overwhelmed — by the hour, by the exertion of climbing, by the spiritual intensity of Jesus''s prayer. "When they were awake" (diagrēgorēsantes — having stayed fully awake, roused themselves thoroughly). Luke notes they saw "his glory" (tēn doxan autou) — a witness to the divine nature of the Transfigured One. The same drowsiness will afflict them in Gethsemane (22:45-46), with tragic consequences.', NULL),
  (33, 'And it came to pass, as they departed from him, Peter said unto Jesus, Master, it is good for us to be here: and let us make three tabernacles; one for thee, and one for Moses, and one for Elias: not knowing what he said.', 'καὶ ἐγένετο ἐν τῷ διαχωρίζεσθαι αὐτοὺς ἀπ'' αὐτοῦ εἶπεν ὁ Πέτρος πρὸς τὸν Ἰησοῦν, Ἐπιστάτα, καλόν ἐστιν ἡμᾶς ὧδε εἶναι· καὶ ποιήσωμεν σκηνὰς τρεῖς, μίαν σοι καὶ μίαν Μωϋσεῖ καὶ μίαν Ἠλίᾳ· μὴ εἰδὼς ὃ λέγει.', 'kai egeneto en tō diachōrizesthai autous ap'' autou eipen ho Petros pros ton Iēsoun, Epistata, kalon estin hēmas hōde einai; kai poiēsōmen skēnas treis, mian soi kai mian Mōusei kai mian Ēlia; mē eidōs ho legei.', '"Three tabernacles" (skēnas — tents, booths). Peter wants to build structures to prolong the glorious experience and to honor the three figures equally. But Luke adds "not knowing what he said" — a gentle rebuke. To equate Jesus with Moses and Elijah in three equal booths is a category error. The divine voice (v.35) will correct it: Jesus alone is the Son; Moses and Elijah are servants. The Feast of Tabernacles (Sukkoth) background — the booths — is likely intended, pointing to the eschatological dwelling of God with his people.', NULL),
  (34, 'While he thus spake, there came a cloud, and overshadowed them: and they feared as they entered into the cloud.', 'ταῦτα δὲ αὐτοῦ λέγοντος ἐγένετο νεφέλη καὶ ἐπεσκίαζεν αὐτούς· ἐφοβήθησαν δὲ ἐν τῷ εἰσελθεῖν αὐτοὺς εἰς τὴν νεφέλην.', 'tauta de autou legontes egeneto nephelē kai epeskiazen autous; ephobēthēsan de en tō eiselthein autous eis tēn nephelēn.', '"A cloud" (nephelē) — the cloud of the shekinah presence, the pillar of cloud that led Israel through the wilderness (Exod 40:34-38), the cloud that filled Solomon''s temple (1 Kgs 8:10-11). It is the divine presence made visible. "Overshadowed them" (epeskiazen — as the Spirit overshadowed Mary in 1:35). The disciples enter the cloud — they are immersed in the divine presence — and fear appropriately.', NULL),
  (35, 'And there came a voice out of the cloud, saying, This is my beloved Son: hear him.', 'καὶ φωνὴ ἐγένετο ἐκ τῆς νεφέλης λέγουσα, Οὗτός ἐστιν ὁ Υἱός μου ὁ ἐκλελεγμένος· αὐτοῦ ἀκούετε.', 'kai phōnē egeneto ek tēs nephelēs legousa, Houtos estin ho Huios mou ho eklelegmenos; autou akouete.', 'The divine voice from the cloud (as at the Baptism, 3:22) gives the definitive answer to the question of Jesus''s identity. "My beloved Son" confirms the Baptism declaration. "Whom I have chosen" (eklelegmenos — elected, the chosen one) echoes Isaiah 42:1 (the Servant). "Hear him" (autou akouete) — the plural command to the three disciples, but applicable to all. It directly answers the Parable of the Sower''s call: this is the one whose word must be heard and kept. The Father himself commands it.', NULL),
  (36, 'And when the voice was past, Jesus was found alone. And they kept it close, and told no man in those days any of those things which they had seen.', 'καὶ ἐν τῷ γενέσθαι τὴν φωνὴν εὑρέθη Ἰησοῦς μόνος. καὶ αὐτοὶ ἐσίγησαν καὶ οὐδενὶ ἀπήγγειλαν ἐν ἐκείναις ταῖς ἡμέραις οὐδὲν ὧν ἑώρακαν.', 'kai en tō genesthai tēn phōnēn heurethē Iēsous monos. kai autoi esigēsan kai oudeni apēngeilan en ekeinais tais hēmerais ouden hōn heōrakasin.', '"Jesus was found alone" — Moses and Elijah have vanished. Only Jesus remains. The law and the prophets have served their purpose as witnesses; the Son supersedes them. "They kept it close" — the command to silence (cf. v.21) is respected. They told no one "in those days" — implying they spoke of it after the resurrection (cf. Mark 9:9: "until the Son of Man be risen from the dead"). The Transfiguration makes full sense only in resurrection light.', NULL),
  (37, 'And it came to pass, that on the next day, when they were come down from the hill, much people met him.', 'Ἐγένετο δὲ τῇ ἑξῆς ἡμέρᾳ κατελθόντων αὐτῶν ἀπὸ τοῦ ὄρους συνήντησεν αὐτῷ ὄχλος πολύς.', 'Egeneto de tē hexēs hēmera katelthontōn autōn apo tou orous sunēntēsen autō ochlos polus.', 'The descent from the mountain of Transfiguration into the valley of human suffering creates a deliberate theological contrast. Moses descended from Sinai to find the people in idolatrous chaos (Exod 32). Jesus descends to find a desperate father and a powerless church. The glory on the mountain is not an escape from human need but the empowerment for engagement with it.', NULL),
  (38, 'And, behold, a man of the company cried out, saying, Master, I beseech thee, look upon my son: for he is mine only child.', 'καὶ ἰδοὺ ἀνὴρ ἀπὸ τοῦ ὄχλου ἐβόησεν λέγων, Διδάσκαλε, δέομαί σου, ἐπιβλέψαι ἐπὶ τὸν υἱόν μου, ὅτι μονογενής μοί ἐστιν·', 'kai idou anēr apo tou ochlou eboēsen legōn, Didaskale, deomai sou, epiblepsai epi ton huion mou, hoti monogenēs moi estin;', '"Only child" (monogenēs) — the third time in Luke 9 this word is used (7:12 for the widow''s son; 8:42 for Jairus''s daughter). Luke deliberately uses this word to prepare for its application to Jesus (John 3:16). The father''s cry (eboēsen — shouted loudly) cuts through the crowd. His desperation and his focus on the uniqueness of the child amplifies the pathos and urgency.', NULL),
  (39, 'And, lo, a spirit taketh him, and he suddenly crieth out; and it teareth him that he foameth again, and bruising him hardly departeth from him.', 'καὶ ἰδοὺ πνεῦμα λαμβάνει αὐτόν, καὶ ἐξαίφνης κράζει, καὶ σπαράσσει αὐτὸν μετὰ ἀφροῦ, καὶ μόγις ἀποχωρεῖ ἀπ'' αὐτοῦ συντρῖβον αὐτόν·', 'kai idou pneuma lambanei auton, kai exaiphnēs krazei, kai sparassei auton meta aphrou, kai mogis apochōrei ap'' autou suntribon auton;', 'The description of the demonic seizures is medically precise: sudden onset (exaiphnēs), crying out (krazei), convulsive shaking (sparassei — convulsion, tearing), foaming (aphrou), and extreme violence leaving the boy bruised and exhausted. Luke the physician observes these symptoms carefully. The spirit hardly departs (mogis apochōrei — barely goes away, implying it always returns). This is a chronic, entrenched possession resisting all human intervention.', NULL),
  (40, 'And I besought thy disciples to cast him out; and they could not.', 'καὶ ἐδεήθην τῶν μαθητῶν σου ἵνα ἐκβάλωσιν αὐτό, καὶ οὐκ ἠδυνήθησαν.', 'kai edeēthēn tōn mathētōn sou hina ekbalōsin auto, kai ouk ēdunēthēsan.', '"They could not" (ouk ēdunēthēsan) — the disciples who had just returned from a successful mission (v.6: healing everywhere) are now unable to cast out a single demon. Their failure is not a permanent state but a diagnostic one: it reveals prayerlessness and faithlessness (v.41; Mark 9:29: "this kind goeth not out but by prayer"). Spiritual power is not accumulated; it is moment-by-moment dependence on the Lord.', NULL),
  (41, 'And Jesus answering said, O faithless and perverse generation, how long shall I be with you, and suffer you? Bring thy son hither.', 'ἀποκριθεὶς δὲ ὁ Ἰησοῦς εἶπεν, Ὦ γενεὰ ἄπιστος καὶ διεστραμμένη, ἕως πότε ἔσομαι πρὸς ὑμᾶς καὶ ἀνέξομαι ὑμῶν; προσάγαγέ μου τὸν υἱόν σου.', 'apokritheis de ho Iēsous eipen, Ō genea apistos kai diestrammenē, heōs pote esomai pros humas kai anexomai humōn? prosagagē mou ton huion sou.', '"O faithless and perverse generation" — a lament echoing Moses''s cry over Israel (Deut 32:5,20). The address appears to encompass the disciples, the crowd, and the era. "How long shall I be with you?" — the language of divine patience stretched to the limit, looking forward to the cross and departure that will transform this failing generation into the empowered church of Acts. "Bring thy son hither" — the command cuts through the situation and brings resolution.', NULL),
  (42, 'And as he was yet a coming, the devil threw him down, and tare him. And Jesus rebuked the unclean spirit, and healed the child, and delivered him again to his father.', 'ἔτι δὲ προσερχομένου αὐτοῦ ἔρριψεν αὐτὸν τὸ δαιμόνιον καὶ συνεσπάραξεν· ἐπετίμησεν δὲ ὁ Ἰησοῦς τῷ πνεύματι τῷ ἀκαθάρτῳ, καὶ ἰάσατο τὸν παῖδα καὶ ἀπέδωκεν αὐτὸν τῷ πατρὶ αὐτοῦ.', 'eti de proserchomenou autou erripsen auton to daimonion kai sunespharaxen; epetimēsen de ho Iēsous tō pneumati tō akathartō, kai iasato ton paida kai apedōken auton tō patri autou.', '"The devil threw him down" in a final violent convulsion as the boy approached Jesus — a last act of demonic defiance before defeat. Jesus "rebuked the unclean spirit" (epetimēsen — the same verb used in 4:35,39 and 8:24) and healed the child. "Delivered him again to his father" — the same phrase as the Nain resurrection (7:15). The echo is deliberate: demonic deliverance and physical resurrection are both acts of the same life-giving Lord.', NULL),
  (43, 'And they were all amazed at the mighty power of God. But while they wondered every one at all things which Jesus did, he said unto his disciples,', 'ἐξεπλήσσοντο δὲ πάντες ἐπὶ τῇ μεγαλειότητι τοῦ Θεοῦ. πάντων δὲ θαυμαζόντων ἐπὶ πᾶσιν οἷς ἐποίει, εἶπεν πρὸς τοὺς μαθητὰς αὐτοῦ,', 'exeplēssonto de pantes epi tē megaleihotēti tou Theou. pantōn de thaumazontōn epi pasin hois epoiei, eipen pros tous mathētas autou,', '"Mighty power of God" (megaleihotēti tou Theou — the majesty, greatness of God). The crowd attributes the miracle to God — a correct response. But while they are still marveling, Jesus immediately pivots to address his disciples with the second passion prediction. The juxtaposition is deliberate: the crowd glorifies God for the miracle; Jesus uses the moment of maximum fame to announce his impending suffering. The pattern of power through humility continues.', NULL),
  (44, 'Let these sayings sink down into your ears: for the Son of man shall be delivered into the hands of men.', 'Θέσθε ὑμεῖς εἰς τὰ ὦτα ὑμῶν τοὺς λόγους τούτους· ὁ γὰρ Υἱὸς τοῦ ἀνθρώπου μέλλει παραδίδοσθαι εἰς χεῖρας ἀνθρώπων.', 'Thesthe humeis eis ta ōta humōn tous logous toutous; ho gar Huios tou anthrōpou mellei paradidosthai eis cheiras anthrōpōn.', '"Let these sayings sink down into your ears" (Thesthe eis ta ōta — set/place in your ears). The imperative is emphatic: make this a priority, store it carefully. "Shall be delivered" (paradidosthai — to be handed over, betrayed). The word is used throughout the passion narrative. The contrast between "Son of Man" and "hands of men" is deliberately ironic: the divine-human figure is delivered into the power of mere humans. This is the deepest paradox of the Incarnation.', NULL),
  (45, 'But they understood not this saying, and it was hid from them, that they perceived it not: and they feared to ask him of that saying.', 'οἱ δὲ ἠγνόουν τὸ ῥῆμα τοῦτο, καὶ ἦν παρακεκαλυμμένον ἀπ'' αὐτῶν ἵνα μὴ αἴσθωνται αὐτό, καὶ ἐφοβοῦντο ἐρωτῆσαι αὐτὸν περὶ τοῦ ῥήματος τούτου.', 'hoi de ēgnooun to rhēma touto, kai ēn parakalummenon ap'' autōn hina mē aisthōntai auto, kai ephobunto erōtēsai auton peri tou rhēmatos toutou.', '"It was hid from them" (parakalummenon — veiled, covered over) — divine passivity: God conceal it from them until the proper time (cf. 18:34; 24:16,25,31,45). The disciples could not yet receive the full weight of the cross without losing all hope; the unveiling would come with the resurrection. "They feared to ask" — their incomprehension was mixed with reluctance to hear the answer. Sometimes we fear to understand what we sense will require too much of us.', NULL),
  (46, 'Then there arose a reasoning among them, which of them should be greatest.', 'Εἰσῆλθεν δὲ διαλογισμὸς ἐν αὐτοῖς, τὸ τίς ἂν εἴη μείζων αὐτῶν.', 'Eisēlthen de dialogismos en autois, to tis an eiē meizōn autōn.', '"There arose a reasoning" (eisēlthen dialogismos — a debate, reasoning entered among them). In the context of Jesus''s just-announced death, the disciples are arguing about greatness. The jarring irony is Luke''s point: immediately after the announcement that Jesus would be handed over to death, the disciples competed for the top position. The passion is incomprehensible to them; the kingdom they are imagining is still a political hierarchy.', NULL),
  (47, 'And Jesus, perceiving the thought of their heart, took a child, and set him by him,', 'ὁ δὲ Ἰησοῦς εἰδὼς τὸν διαλογισμὸν τῆς καρδίας αὐτῶν, ἐπιλαβόμενος παιδίον ἔστησεν αὐτὸ παρ'' ἑαυτῷ,', 'ho de Iēsous eidōs ton dialogismon tēs kardias autōn, epilabomenos paidion estēsen auto par'' heautō,', '"Perceiving the thought of their heart" — Jesus knows unexpressed thoughts (5:22; 6:8; 7:39-40). He does not address the dispute verbally but with a visual parable: he places a child (paidion — a small child) beside himself. In the ancient world, children had no social status, no rights, and no earning capacity. A child was the quintessential non-person in terms of social importance.', NULL),
  (48, 'And said unto them, Whosoever shall receive this child in my name receiveth me: and whosoever shall receive me receiveth him that sent me: for he that is least among you all, the same shall be great.', 'καὶ εἶπεν αὐτοῖς, Ὃς ἐὰν δέξηται τοῦτο τὸ παιδίον ἐπὶ τῷ ὀνόματί μου, ἐμὲ δέχεται· καὶ ὃς ἂν ἐμὲ δέξηται, δέχεται τὸν ἀποστείλαντά με· ὁ γὰρ μικρότερος ἐν πᾶσιν ὑμῖν ὑπάρχων, οὗτος ἔσται μέγας.', 'kai eipen autois, Hos ean dexētai touto to paidion epi tō onomati mou, eme dechetai; kai hos an eme dexētai, dechetai ton aposteilanta me; ho gar mikroteros en pasin humin huparchōn, houtos estai megas.', 'A three-stage chain of identification: to receive this child = to receive Jesus = to receive the Father who sent Jesus. Greatness in the kingdom is measured by willingness to receive and serve the powerless, the marginal, the least — "in my name" (service as a representative of Christ''s character, not as a career strategy). "He that is least among you all, the same shall be great" — the absolute inversion of worldly status hierarchies.', NULL),
  (49, 'And John answered and said, Master, we saw one casting out devils in thy name; and we forbad him, because he followeth not with us.', 'ἀποκριθεὶς δὲ Ἰωάννης εἶπεν, Ἐπιστάτα, εἴδομέν τινα ἐπὶ τῷ ὀνόματί σου ἐκβάλλοντα τὰ δαιμόνια, καὶ ἐκωλύσαμεν αὐτόν, ὅτι οὐκ ἀκολουθεῖ μεθ'' ἡμῶν.', 'apokritheis de Iōannēs eipen, Epistata, eidomen tina epi tō onomati sou ekballonta ta daimonia, kai ekōlusamen auton, hoti ouk akolouthei meth'' hēmōn.', 'John''s confession is connected to the previous teaching: we forbade someone who was doing kingdom work because he was not in our group. The disciples'' sectarianism ("followeth not with us") reveals the same spirit of exclusivity just rebuked in the greatness dispute. They had just failed to cast out a demon (v.40), but they stopped someone who succeeded, because of group identity. The irony is acute.', NULL),
  (50, 'And Jesus said unto him, Forbid him not: for he that is not against us is for us.', 'εἶπεν δὲ πρὸς αὐτὸν ὁ Ἰησοῦς, Μὴ κωλύετε· ὃς γὰρ οὐκ ἔστιν καθ'' ἡμῶν, ὑπὲρ ἡμῶν ἐστιν.', 'eipen de pros auton ho Iēsous, Mē kōluete; hos gar ouk estin kath'' hēmōn, huper hēmōn estin.', '"He that is not against us is for us" — a maxim of kingdom generosity. The complement (12:30/Matt 12:30: "He that is not with me is against me") addresses those who are neutral or hostile; this verse addresses those who are working in the name of Jesus. Kingdom work done in Jesus''s name belongs to the kingdom, regardless of institutional affiliation. The disciples had made group identity the criterion of authenticity; Jesus makes fruit (effective exorcism) the criterion.', NULL),
  (51, 'And it came to pass, when the time was come that he should be received up, he stedfastly set his face to go to Jerusalem,', 'Ἐγένετο δὲ ἐν τῷ συμπληροῦσθαι τὰς ἡμέρας τῆς ἀναλήψεως αὐτοῦ, καὶ αὐτὸς τὸ πρόσωπον ἐστήρισεν τοῦ πορεύεσθαι εἰς Ἱερουσαλήμ,', 'Egeneto de en tō sumplērousthai tas hēmeras tēs analēpseōs autou, kai autos to prosōpon estērisen tou poreuesthai eis Hierousalēm,', 'The great Lukan hinge: v.51 initiates the "Travel Narrative" or "Journey to Jerusalem" (9:51-19:44) — a 10-chapter section unique to Luke. "Was come that he should be received up" (analēpseōs — ascension/taking up) — the entire journey is framed from the perspective of the Ascension, not merely the cross. "Stedfastly set his face" (to prosōpon estērisen — fixed/set his face, like flint — Isa 50:7) — absolute determination and resolve.', NULL),
  (52, 'And sent messengers before his face: and they went, and entered into a village of the Samaritans, to make ready for him.', 'καὶ ἀπέστειλεν ἀγγέλους πρὸ προσώπου αὐτοῦ· καὶ πορευθέντες εἰσῆλθον εἰς κώμην Σαμαρειτῶν, ὥστε ἑτοιμάσαι αὐτῷ·', 'kai apesteilen angelous pro prosōpou autou; kai poreuthentes eisēlthon eis kōmēn Samaritōn, hōste etoimasai autō;', '"Messengers before his face" (angelous pro prosōpou — literally: angels/messengers before his face). The language echoes the messenger saying (7:27: "I send my messenger before thy face"). Jesus''s advance preparation team enters a Samaritan village — another ethnic boundary crossing. Samaritans were despised by Jews and vice versa (John 4:9). The rejection that follows (v.53) anticipates the larger rejection at Jerusalem.', NULL),
  (53, 'And they did not receive him, because his face was as though he would go to Jerusalem.', 'καὶ οὐκ ἐδέξαντο αὐτόν, ὅτι τὸ πρόσωπον αὐτοῦ ἦν πορευόμενον εἰς Ἱερουσαλήμ.', 'kai ouk edexanto auton, hoti to prosōpon autou ēn poreuomenon eis Hierousalēm.', '"Did not receive him" — the Samaritans refused hospitality because Jesus was headed for Jerusalem, the Jewish holy city they considered illegitimate (cf. John 4:20). Their rejection was based on theological rivalry, not personal animosity. Luke will later present a Samaritan as the exemplary neighbor (10:33) and ten lepers as a group where only the Samaritan returned to give thanks (17:16) — consistent reframing of Samaritan-Jewish boundaries.', NULL),
  (54, 'And when his disciples James and John saw this, they said, Lord, wilt thou that we command fire to come down from heaven, and consume them, even as Elias did?', 'ἰδόντες δὲ οἱ μαθηταὶ Ἰάκωβος καὶ Ἰωάννης εἶπον, Κύριε, θέλεις εἴπωμεν πῦρ καταβῆναι ἀπὸ τοῦ οὐρανοῦ καὶ ἀναλῶσαι αὐτούς, ὡς καὶ Ἡλίας ἐποίησεν;', 'idontes de hoi mathētai Iakōbos kai Iōannēs eipon, Kurie, theleis eipōmen pur katabenai apo tou ouranou kai analōsai autous, hōs kai Ēlias epoiēsen?', 'James and John — named "Boanerges" (Sons of Thunder) by Jesus (Mark 3:17) — demonstrate why. Their reference to Elijah''s fire (2 Kgs 1:10-12) reveals the Old Covenant reflex: judgment on rejection. But Jesus has come not to destroy but to seek and save (19:10). Just five verses earlier, Elijah appeared at the Transfiguration discussing the Exodus — the liberation, not the incineration. The same disciples are now proposing exactly what Jesus''s mission overturns.', NULL),
  (55, 'But he turned, and rebuked them, and said, Ye know not what manner of spirit ye are of.', 'στραφεὶς δὲ ἐπετίμησεν αὐτοῖς.', 'strapheis de epetimēsen autois.', '"He turned and rebuked them" — the same verb epetimao used for rebuking demons (4:35,41; 8:24; 9:42) and the storm (8:24). The disciples'' retaliatory spirit is treated as something requiring the same authoritative rebuke applied to unclean powers. The longer textual tradition adds "Ye know not what manner of spirit ye are of" — they were operating from a spirit of vengeance, not the Spirit of the Son of Man who came to save.', NULL),
  (56, 'For the Son of man is not come to destroy men''s lives, but to save them. And they went to another village.', 'καὶ ἐπορεύθησαν εἰς ἑτέραν κώμην.', 'kai eporeuethēsan eis heteran kōmēn.', '"The Son of man is not come to destroy men''s lives, but to save them" (in the longer textual tradition). This mission statement — saving not destroying — is the interpretive key to the entire Travel Narrative. Rejection does not trigger retaliation; it redirects mission. "They went to another village" — Jesus moves on without vengeance. His face is still set toward Jerusalem. Neither rejection nor the disciples'' failures alter his determination.', NULL),
  (57, 'And it came to pass, that, as they went in the way, a certain man said unto him, Lord, I will follow thee whithersoever thou goest.', 'Ἐγένετο δὲ πορευομένων αὐτῶν ἐν τῇ ὁδῷ εἶπέν τις πρὸς αὐτόν, Ἀκολουθήσω σοι ὅπου ἐὰν ἀπέρχῃ, Κύριε.', 'Egeneto de poreuomenōn autōn en tē hodō eipen tis pros auton, Akolouthēsō soi hopou ean aperchē, Kurie.', '"Whithersoever thou goest" — an enthusiastic, unlimited offer. The would-be follower volunteers spontaneously. But his offer may be based on romanticized expectations. Jesus''s response is not discouragement but realism: he offers a clear-eyed picture of what following him actually involves. The three sayings that follow (vv.57-62) are a trilogy of discipleship cost.', NULL),
  (58, 'And Jesus said unto him, Foxes have holes, and birds of the air have nests; but the Son of man hath not where to lay his head.', 'καὶ εἶπεν αὐτῷ ὁ Ἰησοῦς, Αἱ ἀλώπεκες φωλεοὺς ἔχουσιν, καὶ τὰ πετεινὰ τοῦ οὐρανοῦ κατασκηνώσεις· ὁ δὲ Υἱὸς τοῦ ἀνθρώπου οὐκ ἔχει ποῦ τὴν κεφαλὴν κλίνῃ.', 'kai eipen autō ho Iēsous, Hai alōpekes phōleous echousin, kai ta peteina tou ouranou kataskēnōseis; ho de Huios tou anthrōpou ouk echei pou tēn kephalēn klinē.', '"No place to lay his head" — the Creator has no home; the Lord of the universe has no bed. This radical homelessness is not incidental but representative. Jesus has given up all earthly security to accomplish his mission. To follow him is to accept the same. The contrast between animal creatures (foxes, birds) that have homes and the Son of Man who does not is deliberately paradoxical and costly.', NULL),
  (59, 'And he said unto another, Follow me. But he said, Lord, suffer me first to go and bury my father.', 'Εἶπεν δὲ πρὸς ἕτερον, Ἀκολούθει μοι. ὁ δὲ εἶπεν, Κύριε, ἐπίτρεψόν μοι ἀπελθόντι πρῶτον θάψαι τὸν πατέρα μου.', 'Eipen de pros heteron, Akolouthei moi. ho de eipen, Kurie, epitrepson moi apelthonti prōton thapsai ton patera mou.', '"Suffer me first to bury my father" — the most sacred filial duty in Jewish culture. Burying one''s father was a commandment that even overrode other religious obligations. However, the father may not yet have died; the man may be saying "let me stay until my father eventually dies, then I''ll follow." Jesus''s response is not callousness toward filial duty but a declaration that the kingdom call supersedes even the most binding human obligation.', NULL),
  (60, 'Jesus said unto him, Let the dead bury their dead: but go thou and preach the kingdom of God.', 'εἶπεν δὲ αὐτῷ, Ἄφες τοὺς νεκροὺς θάψαι τοὺς ἑαυτῶν νεκρούς· σὺ δὲ ἀπελθὼν διάγγελλε τὴν βασιλείαν τοῦ Θεοῦ.', 'eipen de autō, Aphes tous nekrous thapsai tous heautōn nekrous; su de apelthōn diangeile tēn basileian tou Theou.', '"Let the dead bury their dead" — a paradox: those who are spiritually dead can attend to the physical dead; this man who is alive to the kingdom call has a more urgent assignment. "Go thou and preach the kingdom" — the command replaces the burial with proclamation. The kingdom is so urgently needed that even the most legitimate human delay must yield to it. The kingdom''s urgency defines the priorities of those who have been called.', NULL),
  (61, 'And another also said, Lord, I will follow thee; but let me first go bid them farewell, which are at home at my house.', 'Εἶπεν δὲ καὶ ἕτερος, Ἀκολουθήσω σοί, Κύριε· πρῶτον δὲ ἐπίτρεψόν μοι ἀποτάξασθαι τοῖς εἰς τὸν οἶκόν μου.', 'Eipen de kai heteros, Akolouthēsō soi, Kurie; prōton de epitrepson moi apotaxasthai tois eis ton oikon mou.', '"Bid them farewell" — a reasonable-sounding request. Elisha made the same request of Elijah (1 Kgs 19:20) and was permitted. But Jesus''s response is more demanding than Elijah''s. The reference to Elisha''s call is deliberate (cf. Jesus as greater than Elijah established in Luke 4:25-27). The problem is not the farewell itself but the "first" (prōton) — the prioritizing of family loyalty over the kingdom call.', NULL),
  (62, 'And Jesus said unto him, No man, having put his hand to the plough, and looking back, is fit for the kingdom of God.', 'εἶπεν δὲ ὁ Ἰησοῦς, Οὐδεὶς ἐπιβαλὼν τὴν χεῖρα ἐπ'' ἄροτρον καὶ βλέπων εἰς τὰ ὀπίσω εὔθετός ἐστιν τῇ βασιλείᾳ τοῦ Θεοῦ.', 'eipen de ho Iēsous, Oudeis epibalōn tēn cheira ep'' arotron kai blepōn eis ta opisō euthetos estin tē basileia tou Theou.', '"Having put his hand to the plough, and looking back" — a ploughman who looks back produces a crooked furrow. Ploughing requires complete forward-facing attention. "Is fit" (euthetos — suitable, useful). Discipleship requires the same undivided forward orientation. The three sayings together describe the total claims of the kingdom: no homelessness exemption (v.58), no family obligation exemption (v.60), no farewell exemption (v.62). Jesus is setting his face to Jerusalem; his disciples must set theirs likewise.', NULL)
) AS v(verse_number, kjv_text, original_text, transliteration, study_note, doctrinal_note)
WHERE b.name = 'Luke' AND c.chapter_number = 9;

-- ═══════════════════════════════════════════════════
-- LUKE CHAPTER 9 — BACKFILL: Word Studies + Cross References
-- ═══════════════════════════════════════════════════

INSERT INTO word_studies (verse_id, original_word, transliteration, strongs_number, meaning, word_order)
SELECT v.id, w.original_word, w.transliteration, w.strongs_number, w.meaning, w.word_order
FROM verses v JOIN chapters c ON v.chapter_id = c.id JOIN books b ON c.book_id = b.id
CROSS JOIN (VALUES
  (1, 'δύναμιν καὶ ἐξουσίαν', 'dynamin kai exousian', 'G1411/G1849', 'Power and authority — dynamis = inherent ability to effect an outcome; exousia = delegated right to exercise it. Jesus confers both on the Twelve, the first genuine commissioning in Luke.', 1),
  (2, 'κηρύσσειν τὴν βασιλείαν', 'kēryssein tēn basileian', 'G2784/G932', 'To preach the kingdom — herald-proclamation of the reign of God. The sent Twelve carry the same message Jesus carried (4:43).', 2),
  (3, 'μηδὲν αἴρετε', 'mēden airete', 'G142', 'Take nothing — present imperative: continually take nothing. Radical dependence on God through the hospitality of hearers; strips the messenger of every self-sufficient prop.', 3),
  (5, 'ἐκτινάξατε τὸν κονιορτὸν', 'ektinaxate ton koniorton', 'G1621/G2868', 'Shake off the dust — a prophetic sign-act. Pious Jews shook Gentile dust off returning to Israel; here the rejecting town is treated as pagan ground.', 4),
  (7, 'Ἡρῴδης ὁ τετράρχης', 'Hērōdēs ho tetrarchēs', 'G5076', 'Herod the tetrarch — Antipas, son of Herod the Great, ruler of Galilee and Perea. "Perplexed" (diēporei) at Jesus — guilty conscience over John the Baptist still haunts him.', 5),
  (8, 'Ἠλίας ἐφάνη', 'Ēlias ephanē', 'G2243', 'Elijah hath appeared — popular expectation of Elijah''s return before Messiah (Mal 4:5). Luke has already linked John to Elijah (1:17); now the crowds grope toward recognising Jesus.', 6),
  (10, 'ὑπεχώρησεν', 'hypechōrēsen', 'G5298', 'Withdrew privately — Jesus deliberately retreats with his returning missionaries for debrief and rest, a pattern of ministry rhythm.', 7),
  (13, 'ἄρτοι πέντε καὶ ἰχθύες δύο', 'artoi pente kai ichthyes dyo', 'G740/G2486', 'Five loaves and two fishes — meagre peasant rations. Luke preserves all four Gospels'' unanimous detail, the most widely attested miracle (all four Evangelists).', 8),
  (16, 'εὐλόγησεν... κατέκλασεν... ἐδίδου', 'eulogēsen... kateklasen... edidou', 'G2127/G2622/G1325', 'Blessed, broke, gave — the exact eucharistic sequence Luke will repeat at the Last Supper (22:19) and at Emmaus (24:30). The feeding foreshadows the Lord''s Supper and the heavenly banquet.', 9),
  (17, 'κοφίνους δώδεκα', 'kophinous dōdeka', 'G2894/G1427', 'Twelve baskets — kophinos = small wicker travelling-basket. One basket per disciple; the Twelve who began with nothing now carry the abundance of God. Symbolic of Israel''s twelve tribes fed in the wilderness.', 10),
  (18, 'προσευχόμενον κατὰ μόνας', 'proseuchomenon kata monas', 'G4336/G3441', 'Praying alone — Luke''s characteristic note: Jesus''s confessional moments are wrapped in prayer (3:21 baptism; 6:12 choosing twelve; 22:41 Gethsemane).', 11),
  (20, 'τὸν Χριστὸν τοῦ Θεοῦ', 'ton Christon tou Theou', 'G5547/G2316', 'The Christ of God — Peter''s confession. The genitive "of God" stresses divine origin and appointment, heightening the title beyond national messiah to God''s anointed deliverer.', 12),
  (22, 'δεῖ... παθεῖν', 'dei... pathein', 'G1163/G3958', 'Must suffer — dei = divine necessity. The Cross is not tragedy but plan; Luke will repeat this dei throughout the passion narrative (13:33; 17:25; 22:37; 24:7,26,44).', 13),
  (22, 'τῇ τρίτῃ ἡμέρᾳ ἐγερθῆναι', 'tē tritē hēmera egerthēnai', 'G5154/G1453', 'Raised on the third day — aorist passive infinitive. God raises him. The resurrection is promised from the first passion prediction onward; the Cross is inseparable from the empty tomb.', 14),
  (23, 'ἀρνησάσθω ἑαυτόν', 'arnēsasthō heauton', 'G720', 'Let him deny himself — aorist imperative: a decisive renunciation of self-sovereignty. The same verb Peter will use three times denying Jesus (22:57-60); the reverse of true discipleship.', 15),
  (23, 'ἀράτω τὸν σταυρὸν... καθ᾽ ἡμέραν', 'aratō ton stauron... kath'' hēmeran', 'G4716/G2250', 'Take up his cross daily — Luke alone adds "daily" (kath'' hēmeran). Cross-bearing is not a one-time heroic moment but a continuous daily reckoning with death to self.', 16),
  (24, 'ψυχὴν', 'psychēn', 'G5590', 'Life/soul — the paradox pivots on the double sense of psychē: one''s earthly life and one''s eternal soul. Grasping the first loses the second; surrendering the first gains both.', 17),
  (26, 'ἐπαισχυνθῇ', 'epaischynthē', 'G1870', 'Ashamed — strengthened form of aischynomai. The eschatological reciprocity: shame of Christ now meets shame from Christ at his glorious coming.', 18),
  (29, 'τὸ εἶδος τοῦ προσώπου... ἕτερον', 'to eidos tou prosōpou... heteron', 'G1491/G4383', 'Fashion of his face altered — Luke''s phrasing parallels Moses on Sinai (Exod 34:29-30). Jesus''s glory is not borrowed reflection but inherent deity breaking through the veil of flesh.', 19),
  (30, 'Μωσῆς καὶ Ἠλίας', 'Mōsēs kai Ēlias', 'G3475/G2243', 'Moses and Elijah — the Law and the Prophets personified, both of whom had mountain-top theophanies (Sinai, Horeb). Their presence confirms Jesus as the fulfilment of both Testaments.', 20),
  (31, 'ἔξοδον', 'exodon', 'G1841', 'Decease / exodus — Luke''s unique, theologically loaded word. Jesus''s death is a new Exodus, a liberation from the greater bondage of sin and death, accomplished at Jerusalem.', 21),
  (32, 'βεβαρημένοι ὕπνῳ', 'bebarēmenoi hupnō', 'G916/G5258', 'Heavy with sleep — the same disciples will sleep in Gethsemane (22:45). Luke notes the human frailty of the inner circle even at the mountain of glory.', 22),
  (33, 'τρεῖς σκηνάς', 'treis skēnas', 'G4633', 'Three tabernacles — Peter''s impulsive offer echoes Feast of Tabernacles imagery. But Jesus is not one of three; the voice from the cloud corrects Peter: there is only the Son.', 23),
  (35, 'ὁ υἱός μου ὁ ἐκλελεγμένος', 'ho huios mou ho eklelegmenos', 'G5207/G1586', 'My Son, my Chosen — Luke''s distinctive reading (Matthew/Mark: "beloved"). "Chosen" evokes Isaiah''s Servant (Isa 42:1), linking sonship and the suffering servant motif.', 24),
  (35, 'αὐτοῦ ἀκούετε', 'autou akouete', 'G191', 'Hear him — fulfils Deut 18:15: the prophet like Moses whom you must hear. The Father silences debate: attend to the Son alone.', 25),
  (41, 'γενεὰ ἄπιστος καὶ διεστραμμένη', 'genea apistos kai diestrammenē', 'G1074/G571/G1294', 'Faithless and perverse generation — echoing Deut 32:5, Moses''s lament over Israel. Jesus diagnoses the disciples'' failure as a symptom of a deeper generational unbelief.', 26),
  (44, 'θέσθε ὑμεῖς εἰς τὰ ὦτα ὑμῶν', 'thesthe hymeis eis ta ōta hymōn', 'G5087/G3775', 'Let these sayings sink into your ears — literally "place these words into your ears." A Semitic idiom for deliberate retention. Jesus knows they will forget and need the words later.', 27),
  (46, 'διαλογισμὸς... τίς ἂν εἴη μείζων', 'dialogismos... tis an eiē meizōn', 'G1261/G3187', 'Reasoning who should be greatest — dialogismos = internal deliberation. The irony is acute: immediately after hearing of the Cross, they argue about thrones.', 28),
  (48, 'παιδίον', 'paidion', 'G3813', 'Little child — in the social world of the first century, a child had no status, rights, or honour. Jesus''s object-lesson reverses the greatness calculus completely.', 29),
  (50, 'μὴ κωλύετε', 'mē kōluete', 'G2967', 'Forbid not — present imperative with mē: stop forbidding. Narrow sectarianism is rebuked; the kingdom is wider than one''s own band.', 30),
  (51, 'ἐστήρισεν τὸ πρόσωπον', 'estērisen to prosōpon', 'G4741/G4383', 'Steadfastly set his face — Luke''s signature phrase, echoing Isaiah''s Servant ("I set my face like a flint", Isa 50:7). Begins the Travel Narrative (9:51–19:27): Jesus walks deliberately toward the Cross.', 31),
  (54, 'πῦρ... ἀναλῶσαι', 'pyr... analōsai', 'G4442/G355', 'Fire to consume — James and John invoke Elijah''s precedent (2 Kgs 1:10-12). The old-covenant reflex of judgment is out of step with the Son of Man''s saving mission.', 32),
  (58, 'οὐκ ἔχει ποῦ τὴν κεφαλὴν κλίνῃ', 'ouk echei pou tēn kephalēn klinē', 'G2827', 'No place to lay his head — the homelessness of the Messiah. Foxes and birds have more settled security than the Son of Man. Following him means accepting the same.', 33),
  (60, 'ἄφες τοὺς νεκροὺς θάψαι', 'aphes tous nekrous thapsai', 'G863/G3498', 'Let the dead bury the dead — startling paradox: the spiritually dead can handle the physical dead; those alive to the kingdom have a higher call. Kingdom-urgency supersedes even filial duty.', 34),
  (62, 'ἐπ᾽ ἄροτρον... εἰς τὰ ὀπίσω', 'ep'' arotron... eis ta opisō', 'G723/G3694', 'Hand to the plough... looking back — a ploughman who looks back cuts a crooked furrow. Kingdom service requires undivided forward focus; divided loyalty disqualifies.', 35)
) AS w(verse_number, original_word, transliteration, strongs_number, meaning, word_order)
WHERE b.name = 'Luke' AND c.chapter_number = 9 AND v.verse_number = w.verse_number
ON CONFLICT DO NOTHING;

